import { memo } from 'react';
import { motion } from 'framer-motion';
import { Handle, Position } from '@xyflow/react';
import type { NodeProps } from '@xyflow/react';
import * as Icons from 'lucide-react';
import { X } from 'lucide-react';
import { getComponentCost, formatCost } from '../../engine/costEngine';
import { useArchStore } from '../../store/useArchStore';
import { calculateCarbonFootprints, getCarbonHeatmapColor, getCarbonBorderColor } from '../../engine/carbonEngine';
import type { ArchNodeData } from '../../types';

// Dynamic icon resolver
function getIcon(name: string): React.ComponentType<{ size?: number; className?: string }> {
  const icon = (Icons as Record<string, unknown>)[name];
  if (typeof icon === 'function' || (typeof icon === 'object' && icon !== null)) {
    return icon as React.ComponentType<{ size?: number; className?: string }>;
  }
  return Icons.Box;
}

function ArchNodeComponent({ id, data, selected }: NodeProps) {
  const d = data as unknown as ArchNodeData;
  const IconComponent = getIcon(d.icon);
  const greenOpsHeatmap = useArchStore(s => s.greenOpsHeatmap);
  const nodes = useArchStore(s => s.nodes);
  const computedSecurityReport = useArchStore(s => s.computedSecurityReport);

  const healthClass = d.isFailed ? 'failed' : d.isDisabled ? 'disabled' : d.healthStatus;
  const selectedClass = selected ? 'selected' : '';
  const overloadedClass = d.loadPercent > 80 && !d.isFailed ? 'node-overloaded' : '';

  // Calculate cost for display
  const mockNode = { data: d, id, type: 'archNode', position: { x: 0, y: 0 } };
  const cost = getComponentCost(mockNode as never);

  // GreenOps heatmap coloring
  let heatmapStyle: React.CSSProperties = {};
  let carbonBadge: React.ReactNode = null;

  if (greenOpsHeatmap && !d.isFailed && !d.isDisabled) {
    const footprints = calculateCarbonFootprints(nodes);
    const fp = footprints.find(f => f.nodeId === id);
    if (fp) {
      heatmapStyle = {
        background: getCarbonHeatmapColor(fp.rating),
        boxShadow: `0 0 12px ${getCarbonBorderColor(fp.rating)}20, inset 0 0 0 1px ${getCarbonBorderColor(fp.rating)}30`,
      };
      carbonBadge = (
        <div className="arch-node-carbon-badge" style={{ 
          color: getCarbonBorderColor(fp.rating),
          background: getCarbonHeatmapColor(fp.rating),
          border: `1px solid ${getCarbonBorderColor(fp.rating)}40`,
        }}>
          {fp.monthlyCO2kg < 1 ? `${Math.round(fp.monthlyCO2kg * 1000)}g` : `${fp.monthlyCO2kg.toFixed(1)}kg`} CO₂
        </div>
      );
    }
  }

  // Security Vulnerability Badge
  let securityBadge: React.ReactNode = null;
  if (computedSecurityReport && !d.isFailed && !d.isDisabled) {
    const findings = computedSecurityReport.findings.filter((f: any) => f.affectedNodeIds.includes(id));
    if (findings.length > 0) {
      const hasCritical = findings.some((f: any) => f.severity === 'critical');
      const hasHigh = findings.some((f: any) => f.severity === 'high');
      const color = hasCritical ? '#ff4444' : hasHigh ? '#ff8c00' : '#fbbf24';
      securityBadge = (
        <div className="arch-node-security-badge-container" onClick={(e) => {
          e.stopPropagation();
          useArchStore.getState().selectNode(id);
          useArchStore.setState({ securityPanelOpen: true });
        }}>
          <div className="arch-node-security-badge" style={{ border: `1px solid ${color}` }} title={`${findings.length} security finding(s). Click to view details.`}>
            <Icons.ShieldAlert size={16} color={color} />
          </div>
        </div>
      );
    }
  }

  // Deployment version badge
  const versionBadge = d.appVersion ? (
    <div className={`arch-node-version-badge ${d.appVersion === 'v1' ? 'blue' : 'green'}`}>
      {d.appVersion === 'v1' ? 'BLUE' : 'GREEN'}
    </div>
  ) : null;

  return (
    <motion.div 
      className={`arch-node ${healthClass} ${selectedClass} ${overloadedClass}`}
      data-category={d.category}
      style={heatmapStyle}
      initial={{ scale: 0.95, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      layout
      transition={{ type: 'spring', stiffness: 350, damping: 25 }}
    >
      <Handle type="target" position={Position.Left} />
      <Handle type="source" position={Position.Right} />

      {d.isFailed && (
        <div className="arch-node-failed-overlay">
          <X size={24} />
        </div>
      )}

      {d.instances > 1 && (
        <div className="arch-node-instances">{d.instances}x</div>
      )}

      {versionBadge}
      {carbonBadge}
      {securityBadge}

      <div className="arch-node-header">
        <IconComponent size={18} className="arch-node-icon" />
        <span className="arch-node-label">{d.label}</span>
      </div>

      <div className="arch-node-meta">
        <span className="arch-node-tier">{d.tier.label}</span>
        <span className="arch-node-cost">{formatCost(cost)}</span>
      </div>

      <div className="arch-node-load-bar">
        <div 
          className={`arch-node-load-fill ${d.healthStatus}`}
          style={{ width: `${Math.min(100, d.loadPercent)}%` }}
        />
      </div>
    </motion.div>
  );
}

export default memo(ArchNodeComponent);

import { memo } from 'react';
import { NodeResizer, Handle, Position } from '@xyflow/react';
import type { NodeProps } from '@xyflow/react';

const groupColors: Record<string, { border: string; bg: string; label: string }> = {
  vpc:              { border: '#a78bfa', bg: 'rgba(167, 139, 250, 0.04)', label: 'VPC' },
  'subnet-public':  { border: '#34d399', bg: 'rgba(52, 211, 153, 0.04)', label: 'Public Subnet' },
  'subnet-private': { border: '#fb923c', bg: 'rgba(251, 146, 60, 0.04)', label: 'Private Subnet' },
  'availability-zone': { border: '#60a5fa', bg: 'rgba(96, 165, 250, 0.04)', label: 'Availability Zone' },
  'on-premises':       { border: '#9ca3af', bg: 'rgba(156, 163, 175, 0.04)', label: 'On-Premises' },
};

function GroupNode({ data, selected }: NodeProps) {
  const d = data as any;
  const groupType = d.componentType || 'vpc';
  const colors = groupColors[groupType] || groupColors.vpc;
  const label = d.label || colors.label;

  return (
    <>
      <NodeResizer
        minWidth={220}
        minHeight={160}
        isVisible={selected}
        lineClassName="group-node-resizer-line"
        handleClassName="group-node-resizer-handle"
        color={colors.border}
      />
      <div
        className="group-node"
        style={{
          borderColor: selected ? colors.border : `${colors.border}66`,
          backgroundColor: colors.bg,
          width: '100%',
          height: '100%',
        }}
      >
        <div className="group-node-label" style={{ color: colors.border }}>
          <span className="group-node-badge" style={{ background: `${colors.border}20`, border: `1px solid ${colors.border}40` }}>
            {colors.label}
          </span>
          <span className="group-node-name">{label}</span>
        </div>
      </div>
      {/* Connection handles */}
      <Handle type="target" position={Position.Left} className="group-node-handle" />
      <Handle type="source" position={Position.Right} className="group-node-handle" />
    </>
  );
}

export default memo(GroupNode);

